definition.script:
pipeline {
    agent any
    parameters {
        choice(name: 'AMBIENTE', choices: ['homolog', 'prod'], description: 'Ambiente a ser atualizado')
    }
    stages {
        stage('Atualizar código') {
            steps {
                dir('/home/univates/aurum-fintech') {
                    sh 'git config --global --add safe.directory /home/univates/aurum-fintech && git pull'
                }
            }
        }
        stage('Deploy') {
            steps {
                dir('/home/univates/aurum-fintech') {
                    sh "chmod +x deploy-${params.AMBIENTE}.sh"
                    sh "./deploy-${params.AMBIENTE}.sh"
                }
            }
        }
    }
    post {
        success { echo "Deploy em ${params.AMBIENTE} concluido com sucesso." }
        failure  { echo "Deploy em ${params.AMBIENTE} falhou." }
    }
}
